function processData() {
  const inputArray = $input.all();

  return inputArray
    .filter(entry => entry.json && entry.json.body && entry.json.body.bind_data)
    .map(entry => {
      const item = entry.json.body;
      let bindData = item.bind_data;
      const parts = bindData.split(',');
      if (parts.length > 1) {
        bindData = parts[1];
      } else {
        bindData = parts[0];
      }
      bindData = bindData.replace(/-/g, '');

      // 放到json里
      return {
        json: {
          ...item,
          bind_id: bindData,
          timelimit:$('Webhook').first().json.body.timelimit
        }
      };
    });
}

return processData();
